+                }
+            }
+            f if f == fields.name => {
+                if let Some(s) = value.as_str() {
+                    name = Some(s.to_string());
+                }
+            }
+            f if f == fields.path => {
+                if let Some(s) = value.as_str() {
+                    path = Some(s.to_string());
+                }
